CREATE TABLE IF NOT EXISTS products (
  id INT AUTO_INCREMENT PRIMARY KEY,
  sku VARCHAR(100) UNIQUE NOT NULL,
  name VARCHAR(255) NOT NULL,
  description TEXT,
  price DECIMAL(10, 2) NOT NULL,
  cost DECIMAL(10, 2) NOT NULL DEFAULT 0,
  stock INT NOT NULL DEFAULT 0,
  reserved INT NOT NULL DEFAULT 0,
  category VARCHAR(100),
  weight_grams INT,
  is_active BOOLEAN DEFAULT true,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS shipments (
  id INT AUTO_INCREMENT PRIMARY KEY,
  order_ref VARCHAR(100) NOT NULL,
  user_email VARCHAR(255) NOT NULL,
  carrier VARCHAR(100) NOT NULL,
  tracking_number VARCHAR(255),
  status VARCHAR(50) NOT NULL DEFAULT 'pending',
  weight_grams INT,
  package_count INT DEFAULT 1,
  destination_street VARCHAR(255),
  destination_city VARCHAR(100),
  destination_state VARCHAR(50),
  destination_zip VARCHAR(10),
  destination_country VARCHAR(2) DEFAULT 'US',
  estimated_delivery DATE,
  actual_delivery TIMESTAMP NULL,
  shipping_cost_cents INT DEFAULT 0,
  insurance_cents INT DEFAULT 0,
  signature_required BOOLEAN DEFAULT false,
  notes TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS notifications (
  id INT AUTO_INCREMENT PRIMARY KEY,
  recipient VARCHAR(255) NOT NULL,
  channel VARCHAR(50) NOT NULL,
  subject VARCHAR(500),
  body TEXT,
  template VARCHAR(100),
  metadata JSON,
  status VARCHAR(50) NOT NULL DEFAULT 'queued',
  priority INT DEFAULT 5,
  retry_count INT DEFAULT 0,
  max_retries INT DEFAULT 3,
  error_message TEXT,
  sent_at TIMESTAMP NULL,
  delivered_at TIMESTAMP NULL,
  opened_at TIMESTAMP NULL,
  clicked_at TIMESTAMP NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS shipment_events (
  id INT AUTO_INCREMENT PRIMARY KEY,
  shipment_id INT NOT NULL,
  event_type VARCHAR(50) NOT NULL,
  location VARCHAR(255),
  description TEXT,
  event_timestamp TIMESTAMP NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (shipment_id) REFERENCES shipments(id)
);

CREATE TABLE IF NOT EXISTS returns (
  id INT AUTO_INCREMENT PRIMARY KEY,
  order_ref VARCHAR(100) NOT NULL,
  user_email VARCHAR(255) NOT NULL,
  reason VARCHAR(100) NOT NULL,
  reason_detail TEXT,
  status VARCHAR(50) NOT NULL DEFAULT 'requested',
  refund_amount_cents INT NOT NULL DEFAULT 0,
  refund_method VARCHAR(50),
  return_tracking VARCHAR(255),
  return_carrier VARCHAR(100),
  items JSON,
  approved_by VARCHAR(255),
  approved_at TIMESTAMP NULL,
  received_at TIMESTAMP NULL,
  refunded_at TIMESTAMP NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS warehouse_inventory (
  id INT AUTO_INCREMENT PRIMARY KEY,
  sku VARCHAR(100) NOT NULL,
  warehouse_code VARCHAR(20) NOT NULL,
  quantity INT NOT NULL DEFAULT 0,
  aisle VARCHAR(10),
  shelf VARCHAR(10),
  bin VARCHAR(10),
  last_counted_at TIMESTAMP NULL,
  last_received_at TIMESTAMP NULL,
  UNIQUE KEY uk_sku_warehouse (sku, warehouse_code)
);

